  ('aboriginal-64311456-moex-00012', 'aboriginal-64311456', 'aboriginal-64311456-moex-114-cc9133e4', 'sub-aboriginal-64311456-03', NULL, 'essay', '請說明「原住民族文化健康站」設立的目的。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "de287171d962", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "502", "s": "0904", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會福利政策與法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00013', 'aboriginal-64311456', 'aboriginal-64311456-moex-114-3082b5f1', 'sub-aboriginal-64311456-04', NULL, 'single_choice', '依司法院大法官解釋意旨，關於法律之敘述，下列何者錯誤？', '["所謂法律，原則上係對不特定人之權利義務所為之抽象規定", "預算案實質上為行政行為之一種，但因具有法律之形式，故稱之為措施性法律", "若法律實際適用結果，僅單一或少數對象受該法律規範者，即為憲法所不許", "法律明確性原則並無禁止立法者衡酌生活事實之複雜性及適用於個案之妥當性，適當運用不確 定法律概念之可能性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "502", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00014', 'aboriginal-64311456', 'aboriginal-64311456-moex-114-3082b5f1', 'sub-aboriginal-64311456-04', NULL, 'single_choice', '關於法律不溯及既往原則之敘述，下列何者錯誤？', '["不論負擔性或授益性法律均有法律不溯及既往之適用", "真正溯及既往係指，法規於時間上向前適用於已確定終結之案件", "原則上法律不溯及既往只禁止真正溯及既往之情形，惟若不真正溯及既往之影響過鉅，則宜制 定過渡條款", "基於重大公益之考量仍可能例外允許制定真正溯及既往之法規"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "502", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00015', 'aboriginal-64311456', 'aboriginal-64311456-moex-114-3082b5f1', 'sub-aboriginal-64311456-04', NULL, 'single_choice', '下列何者非屬不確定法律概念？', '["食品安全衛生管理法第15條之「有毒或含有害人體健康之物質或異物」", "建築法第58條之「危害公共安全者」", "空氣污染防制法第62條之「通知限期補正或改善」", "廢棄物清理法第2條之「有害事業廢棄物」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "502", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00016', 'aboriginal-64311456', 'aboriginal-64311456-moex-114-3082b5f1', 'sub-aboriginal-64311456-04', NULL, 'single_choice', '關於公立中小學與學生之法律關係，下列敘述何者正確？', '["學校不得對學生作成行政處分", "學生與學校成立公法上之營造物利用關係", "學校制定學生退學之校規，無需任何法律依據", "學生與學校間之營造物利用關係發生爭執時，僅得透過家長會協議解決"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:07+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "502", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL)
